export function getServiceBySlug(slug: string): ExtendedServiceItem | undefined {
  return servicesExtended.find(service => service.slug === slug);
}

export function getRelatedServices(service: ExtendedServiceItem, limit = 3): ExtendedServiceItem[] {
  return service.relatedServices
    .map(slug => getServiceBySlug(slug))
    .filter((s): s is ExtendedServiceItem => s !== undefined)
    .slice(0, limit);
}

export function getAllServicesByCategory(categorySlug: string): ExtendedServiceItem[] {
  const categoryMap: Record<string, string> = {
    'especialidades': 'especialidade',
    'exames': 'exame',
    'servicos': 'servico'
  };

  const categoryType = categoryMap[categorySlug];
  return servicesExtended.filter(service => service.category === categoryType);
}
